 1→import { add, distance, normalize, perpendicular, scale, subtract } from '@/geometry/point';
 2→
 3→function getSafeAxis(rawVector) {
 4→  return normalize(rawVector.x || rawVector.y ? rawVector : { x: 1, y: 0 });
 5→}
 6→
 7→function getSupportOffset(instance) {
 8→  return Number.isFinite(instance?.supportOffsetAlongAxis)
 9→    ? Math.max(0, instance.supportOffsetAlongAxis)
10→    : 0;
11→}
12→
13→export function getTrussSupportLength(instance) {
14→  return Math.max(
15→    distance(instance.startPoint, instance.endPoint),
16→    Number(instance.spacing || 0) * Math.max((instance.count || 1) - 1, 0),
17→    1
18→  );
19→}
20→
21→export function resolveTrussLayout(instance) {
22→  const rawVector = subtract(instance.endPoint, instance.startPoint);
23→  const axis = getSafeAxis(rawVector);
24→
25→  return {
26→    axis,
27→    spanDirection: perpendicular(axis),
28→    supportLength: getTrussSupportLength(instance),
29→  };
30→}
31→
32→export function buildTrussCopyOrigins(instance) {
33→  const layout = resolveTrussLayout(instance);
34→  const count = Math.max(1, Math.round(instance.count || 1));
35→  const startOrigin = add(instance.startPoint, scale(layout.axis, getSupportOffset(instance)));
36→
37→  return Array.from({ length: count }, (_, index) => ({
38→    id: `${instance.id}_copy_${index}`,
39→    index,
40→    origin: add(startOrigin, scale(layout.axis, (instance.spacing || 0) * index)),
41→  }));
42→}
