  1→import { createTrussMember, createTrussNode, resolveTrussType } from '@/domain/trussModels';
  2→
  3→const EPSILON = 1e-6;
  4→
  5→function lerp(a, b, t) {
  6→  return a + ((b - a) * t);
  7→}
  8→
  9→function createLocalNodeMap(points, prefix) {
 10→  return points.map((point, index) => createTrussNode(point.x, point.z, {
 11→    id: `${prefix}_${index}`,
 12→    kind: point.kind,
 13→  }));
 14→}
 15→
 16→function addMember(members, startNodeId, endNodeId, memberType, index) {
 17→  if (!startNodeId || !endNodeId || startNodeId === endNodeId) return;
 18→  members.push(createTrussMember(startNodeId, endNodeId, {
 19→    id: `${memberType}_${index}`,
 20→    memberType,
 21→  }));
 22→}
 23→
 24→function distance2d(start, end) {
 25→  const dx = Number(end?.x || 0) - Number(start?.x || 0);
 26→  const dz = Number(end?.z || 0) - Number(start?.z || 0);
 27→  return Math.hypot(dx, dz);
 28→}
 29→
 30→function uniqueOutlinePoints(points = []) {
 31→  const unique = [];
 32→  for (const point of points) {
 33→    if (!Number.isFinite(point?.x) || !Number.isFinite(point?.z)) continue;
 34→    const previous = unique[unique.length - 1];
 35→    if (!previous || distance2d(previous, point) > EPSILON) {
 36→      unique.push(point);
 37→    }
 38→  }
 39→  return unique;
 40→}
 41→
 42→function sampleOutlineAtX(points = [], x = 0) {
 43→  if (!points.length) return { x, z: 0 };
 44→  if (points.length === 1) return { x, z: points[0].z };
 45→
 46→  const ordered = [...points].sort((a, b) => a.x - b.x);
 47→  if (x <= ordered[0].x + EPSILON) return { x, z: ordered[0].z };
 48→  if (x >= ordered[ordered.length - 1].x - EPSILON) return { x, z: ordered[ordered.length - 1].z };
 49→
 50→  for (let index = 0; index < ordered.length - 1; index += 1) {
 51→    const start = ordered[index];
 52→    const end = ordered[index + 1];
 53→    if (x < start.x - EPSILON || x > end.x + EPSILON) continue;
 54→    const span = end.x - start.x;
 55→    if (Math.abs(span) <= EPSILON) {
 56→      return { x, z: end.z };
 57→    }
 58→    const ratio = (x - start.x) / span;
 59→    return {
 60→      x,
 61→      z: lerp(start.z, end.z, ratio),
 62→    };
 63→  }
 64→
 65→  return { x, z: ordered[ordered.length - 1].z };
 66→}
 67→
 68→function createBottomPoints(metrics) {
 69→  return Array.from({ length: metrics.panelCount + 1 }, (_, index) => ({
 70→    x: (metrics.span * index) / metrics.panelCount,
 71→    z: 0,
 72→    kind: 'bottom_chord',
 73→  }));
 74→}
 75→
 76→function buildProfileFromStructuralOutline(metrics, structuralOutline, options = {}) {
 77→  const webMode = options.webMode || (metrics.family === 'gable' ? 'gable' : 'alternating');
 78→  const bottomPoints = createBottomPoints(metrics);
 79→  const topPoints = bottomPoints.map((point, index) => {
 80→    const sampled = sampleOutlineAtX(structuralOutline, point.x);
 81→    return {
 82→      x: point.x,
 83→      z: sampled.z,
 84→      kind: sampled.z >= Math.max(...structuralOutline.map((entry) => entry.z)) - EPSILON
 85→        ? (metrics.family === 'gable' ? 'ridge' : 'top_chord')
 86→        : 'top_chord',
 87→    };
 88→  });
 89→
 90→  const overhangPoints = [
 91→    { x: -metrics.overhangStart, z: structuralOutline[0]?.z || 0, kind: 'overhang' },
 92→    { x: metrics.span + metrics.overhangEnd, z: structuralOutline[structuralOutline.length - 1]?.z || 0, kind: 'overhang' },
 93→  ];
 94→
 95→  const topNodes = createLocalNodeMap(topPoints, 'top');
 96→  const bottomNodes = createLocalNodeMap(bottomPoints, 'bottom');
 97→  const overhangNodes = createLocalNodeMap(overhangPoints, 'overhang');
 98→  const members = [];
 99→
100→  addMember(members, overhangNodes[0].id, topNodes[0].id, 'topChord', members.length);
101→  for (let index = 0; index < topNodes.length - 1; index += 1) {
102→    addMember(members, topNodes[index].id, topNodes[index + 1].id, 'topChord', members.length);
103→  }
104→  addMember(members, topNodes[topNodes.length - 1].id, overhangNodes[1].id, 'topChord', members.length);
105→
106→  for (let index = 0; index < bottomNodes.length - 1; index += 1) {
107→    addMember(members, bottomNodes[index].id, bottomNodes[index + 1].id, 'bottomChord', members.length);
108→  }
109→
110→  for (let index = 1; index < bottomNodes.length - 1; index += 1) {
111→    if (Math.abs(topPoints[index].z - bottomPoints[index].z) <= EPSILON) continue;
112→    addMember(members, bottomNodes[index].id, topNodes[index].id, 'web', members.length);
113→  }
114→
115→  if (webMode === 'gable') {
116→    const midpoint = metrics.panelCount / 2;
117→    for (let index = 0; index < metrics.panelCount; index += 1) {
118→      if (index < midpoint) {
119→        addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
120→        continue;
121→      }
122→      addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
123→    }
124→  } else {
125→    for (let index = 0; index < metrics.panelCount; index += 1) {
126→      if (index % 2 === 0) {
127→        addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
128→        continue;
129→      }
130→      addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
131→    }
132→  }
133→
134→  return {
135→    nodes: [...overhangNodes, ...topNodes, ...bottomNodes],
136→    members,
137→    roofOutline: [
138→      { x: -metrics.overhangStart, z: structuralOutline[0]?.z || 0 },
139→      ...structuralOutline,
140→      { x: metrics.span + metrics.overhangEnd, z: structuralOutline[structuralOutline.length - 1]?.z || 0 },
141→    ],
142→    bottomOutline: bottomPoints,
143→    topChordRuns: options.topChordRuns || [{
144→      id: 'main',
145→      side: 'main',
146→      points: structuralOutline,
147→    }],
148→  };
149→}
150→
151→export function resolveTrussMetrics(instance, trussType = resolveTrussType(instance?.trussTypeId)) {
152→  const family = trussType.family;
153→  const shape = trussType.shape || family;
154→  const span = Math.max(Number(instance?.span || trussType.defaultSpan || 0), 1000);
155→  const run = family === 'gable' ? span / 2 : span;
156→  const defaultPitch = Number(trussType.defaultPitch || 0);
157→  const defaultRise = Number(trussType.defaultRise || 0);
158→  const explicitRise = Number(instance?.rise);
159→  const explicitPitch = Number(instance?.pitch);
160→
161→  if (shape === 'flat') {
162→    const rise = Number.isFinite(explicitRise) ? Math.max(0, explicitRise) : Math.max(0, defaultRise || 900);
163→    return {
164→      family,
165→      shape,
166→      span,
167→      rise,
168→      pitch: 0,
169→      overhangStart: Math.max(Number(instance?.overhangs?.start || 0), 0),
170→      overhangEnd: Math.max(Number(instance?.overhangs?.end || 0), 0),
171→      bearingStart: Number(instance?.bearingOffsets?.start || 0),
172→      bearingEnd: Number(instance?.bearingOffsets?.end || 0),
173→      panelCount: Math.max(2, Math.round(trussType.webPattern?.panelCount || 4)),
174→    };
175→  }
176→
177→  const riseFromPitch = ((Number.isFinite(explicitPitch) ? explicitPitch : defaultPitch) / 100) * Math.max(run, 1);
178→  const rise = Number.isFinite(explicitRise) ? Math.max(0, explicitRise) : Math.max(0, riseFromPitch || defaultRise);
179→  const pitch = Number.isFinite(explicitPitch)
180→    ? Math.max(0, explicitPitch)
181→    : ((rise / Math.max(run, 1)) * 100);
182→
183→  return {
184→    family,
185→    shape,
186→    span,
187→    rise,
188→    pitch,
189→    overhangStart: Math.max(Number(instance?.overhangs?.start || 0), 0),
190→    overhangEnd: Math.max(Number(instance?.overhangs?.end || 0), 0),
191→    bearingStart: Number(instance?.bearingOffsets?.start || 0),
192→    bearingEnd: Number(instance?.bearingOffsets?.end || 0),
193→    panelCount: Math.max(2, Math.round(trussType.webPattern?.panelCount || 4)),
194→  };
195→}
196→
197→function buildGableProfile(metrics) {
198→  const topPoints = [];
199→  for (let index = 0; index <= metrics.panelCount; index += 1) {
200→    const ratio = index / metrics.panelCount;
201→    const x = metrics.span * ratio;
202→    const z = ratio <= 0.5
203→      ? lerp(0, metrics.rise, ratio / 0.5)
204→      : lerp(metrics.rise, 0, (ratio - 0.5) / 0.5);
205→    topPoints.push({ x, z, kind: index === Math.floor(metrics.panelCount / 2) ? 'ridge' : 'top_chord' });
206→  }
207→
208→  const bottomPoints = createBottomPoints(metrics);
209→  const overhangPoints = [
210→    { x: -metrics.overhangStart, z: 0, kind: 'overhang' },
211→    { x: metrics.span + metrics.overhangEnd, z: 0, kind: 'overhang' },
212→  ];
213→
214→  const topNodes = createLocalNodeMap(topPoints, 'top');
215→  const bottomNodes = createLocalNodeMap(bottomPoints, 'bottom');
216→  const overhangNodes = createLocalNodeMap(overhangPoints, 'overhang');
217→  const members = [];
218→
219→  addMember(members, overhangNodes[0].id, topNodes[0].id, 'topChord', members.length);
220→  for (let index = 0; index < topNodes.length - 1; index += 1) {
221→    addMember(members, topNodes[index].id, topNodes[index + 1].id, 'topChord', members.length);
222→  }
223→  addMember(members, topNodes[topNodes.length - 1].id, overhangNodes[1].id, 'topChord', members.length);
224→
225→  for (let index = 0; index < bottomNodes.length - 1; index += 1) {
226→    addMember(members, bottomNodes[index].id, bottomNodes[index + 1].id, 'bottomChord', members.length);
227→  }
228→
229→  for (let index = 1; index < bottomNodes.length - 1; index += 1) {
230→    addMember(members, bottomNodes[index].id, topNodes[index].id, 'web', members.length);
231→  }
232→
233→  const midpoint = Math.floor(metrics.panelCount / 2);
234→  for (let index = 0; index < metrics.panelCount; index += 1) {
235→    if (index < midpoint) {
236→      addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
237→      continue;
238→    }
239→    addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
240→  }
241→
242→  return {
243→    nodes: [...overhangNodes, ...topNodes, ...bottomNodes],
244→    members,
245→    roofOutline: [
246→      { x: -metrics.overhangStart, z: 0 },
247→      ...topPoints,
248→      { x: metrics.span + metrics.overhangEnd, z: 0 },
249→    ],
250→    bottomOutline: bottomPoints,
251→    topChordRuns: [
252→      { id: 'left', side: 'left', points: topPoints.slice(0, midpoint + 1) },
253→      { id: 'right', side: 'right', points: topPoints.slice(midpoint).reverse() },
254→    ],
255→  };
256→}
257→
258→function buildShedProfile(metrics) {
259→  const topPoints = [];
260→  for (let index = 0; index <= metrics.panelCount; index += 1) {
261→    const ratio = index / metrics.panelCount;
262→    topPoints.push({
263→      x: metrics.span * ratio,
264→      z: metrics.rise * ratio,
265→      kind: index === metrics.panelCount ? 'high_point' : 'top_chord',
266→    });
267→  }
268→
269→  const bottomPoints = createBottomPoints(metrics);
270→  const overhangPoints = [
271→    { x: -metrics.overhangStart, z: 0, kind: 'overhang' },
272→    {
273→      x: metrics.span + metrics.overhangEnd,
274→      z: metrics.span > EPSILON ? metrics.rise * ((metrics.span + metrics.overhangEnd) / metrics.span) : metrics.rise,
275→      kind: 'overhang',
276→    },
277→  ];
278→
279→  const topNodes = createLocalNodeMap(topPoints, 'top');
280→  const bottomNodes = createLocalNodeMap(bottomPoints, 'bottom');
281→  const overhangNodes = createLocalNodeMap(overhangPoints, 'overhang');
282→  const members = [];
283→
284→  addMember(members, overhangNodes[0].id, topNodes[0].id, 'topChord', members.length);
285→  for (let index = 0; index < topNodes.length - 1; index += 1) {
286→    addMember(members, topNodes[index].id, topNodes[index + 1].id, 'topChord', members.length);
287→  }
288→  addMember(members, topNodes[topNodes.length - 1].id, overhangNodes[1].id, 'topChord', members.length);
289→
290→  for (let index = 0; index < bottomNodes.length - 1; index += 1) {
291→    addMember(members, bottomNodes[index].id, bottomNodes[index + 1].id, 'bottomChord', members.length);
292→  }
293→
294→  for (let index = 1; index < metrics.panelCount; index += 1) {
295→    addMember(members, bottomNodes[index].id, topNodes[index].id, 'web', members.length);
296→  }
297→
298→  for (let index = 0; index < metrics.panelCount; index += 1) {
299→    if (index % 2 === 0) {
300→      addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
301→      continue;
302→    }
303→    addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
304→  }
305→
306→  return {
307→    nodes: [...overhangNodes, ...topNodes, ...bottomNodes],
308→    members,
309→    roofOutline: [
310→      { x: -metrics.overhangStart, z: 0 },
311→      ...topPoints,
312→      { x: metrics.span + metrics.overhangEnd, z: overhangPoints[1].z },
313→    ],
314→    bottomOutline: bottomPoints,
315→    topChordRuns: [{ id: 'main', side: 'main', points: topPoints }],
316→  };
317→}
318→
319→function buildFlatProfile(metrics) {
320→  const structuralOutline = uniqueOutlinePoints([
321→    { x: 0, z: metrics.rise },
322→    { x: metrics.span, z: metrics.rise },
323→  ]);
324→
325→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
326→    webMode: 'alternating',
327→    topChordRuns: [{ id: 'main', side: 'main', points: structuralOutline }],
328→  });
329→}
330→
331→function buildBoxGableProfile(metrics) {
332→  const crownWidth = Math.max(metrics.span * 0.22, Math.min(metrics.span * 0.3, 1200));
333→  const crownStart = (metrics.span - crownWidth) / 2;
334→  const crownEnd = crownStart + crownWidth;
335→  const structuralOutline = uniqueOutlinePoints([
336→    { x: 0, z: 0 },
337→    { x: crownStart, z: metrics.rise },
338→    { x: crownEnd, z: metrics.rise },
339→    { x: metrics.span, z: 0 },
340→  ]);
341→
342→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
343→    webMode: 'gable',
344→    topChordRuns: [
345→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 2) },
346→      { id: 'right', side: 'right', points: [structuralOutline[3], structuralOutline[2]] },
347→    ],
348→  });
349→}
350→
351→function buildHipSliceProfile(metrics, options = {}) {
352→  const supportLength = Math.max(Number(options.supportLength || 0), 0);
353→  const layoutOffset = Math.max(Number(options.layoutOffset || 0), 0);
354→  const halfSpan = Math.max(metrics.span / 2, EPSILON);
355→  const endDistance = supportLength > EPSILON
356→    ? Math.max(0, Math.min(layoutOffset, supportLength - layoutOffset))
357→    : halfSpan;
358→  const clippedRun = Math.max(0, Math.min(halfSpan, endDistance));
359→  const localRise = metrics.rise * (clippedRun / halfSpan);
360→
361→  if (clippedRun <= EPSILON || localRise <= EPSILON) {
362→    return buildFlatProfile({
363→      ...metrics,
364→      rise: 0,
365→    });
366→  }
367→
368→  if (clippedRun >= halfSpan - EPSILON) {
369→    return buildGableProfile(metrics);
370→  }
371→
372→  const crownStart = clippedRun;
373→  const crownEnd = metrics.span - clippedRun;
374→  const structuralOutline = uniqueOutlinePoints([
375→    { x: 0, z: 0 },
376→    { x: crownStart, z: localRise },
377→    { x: crownEnd, z: localRise },
378→    { x: metrics.span, z: 0 },
379→  ]);
380→
381→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
382→    webMode: 'gable',
383→    topChordRuns: [
384→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 2) },
385→      { id: 'right', side: 'right', points: [structuralOutline[3], structuralOutline[2]] },
386→    ],
387→  });
388→}
389→
390→function buildHipProfile(metrics) {
391→  return buildGableProfile(metrics);
392→}
393→
394→function buildDroppedEavesProfile(metrics) {
395→  const heelInset = Math.max(metrics.span * 0.12, Math.min(metrics.span * 0.18, 900));
396→  const heelHeight = Math.max(metrics.rise * 0.32, 250);
397→  const structuralOutline = uniqueOutlinePoints([
398→    { x: 0, z: 0 },
399→    { x: heelInset, z: heelHeight },
400→    { x: metrics.span / 2, z: metrics.rise },
401→    { x: metrics.span - heelInset, z: heelHeight },
402→    { x: metrics.span, z: 0 },
403→  ]);
404→
405→  return buildProfileFromStructuralOutline(metrics, structuralOutline, {
406→    webMode: 'gable',
407→    topChordRuns: [
408→      { id: 'left', side: 'left', points: structuralOutline.slice(0, 3) },
409→      { id: 'right', side: 'right', points: [structuralOutline[4], structuralOutline[3], structuralOutline[2]] },
410→    ],
411→  });
412→}
