 69→function buildDoorTags(doors = [], walls = []) {
 70→  return doors
 71→    .map((door, index) => {
 72→      const wall = walls.find((entry) => entry.id === door.wallId);
 73→      if (!wall) return null;
 74→      const info = doorOutlineOnWall(wall, door);
 75→      const offset = scale(perpendicular(wallDirection(wall)), wall.thickness / 2 + 180);
 76→      return createTag(
 77→        `door-tag-${door.id}`,
 78→        [`D${index + 1}`],
 79→        add(info.center, offset),
 80→        { sourceType: 'door', sourceId: door.id, priority: 0 }
 81→      );
 82→    })
 83→    .filter(Boolean);
 84→}
